var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF002S07071-10\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 서찰","JPN":"CN No. VCDF002S07071-10\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: 対象者書札","ENG":"CN No. VCDF002S07071-10\\n<color=#ffd34c>Class 1 Subject</color> Canonization Materials\\nAppendix: Subject Correspondence","TWN":"(TWN)CN No. VCDF002S07071-10\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 서찰"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"루퍼 자매님, 잘 지내고 있나요?","JPN":"ルーパー姉妹様、うまく行っているの?","ENG":"Sister Looper, how have you been?","TWN":"(TWN)루퍼 자매님, 잘 지내고 있나요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"도착해서 처음으로 편지를 적어 봅니다.","JPN":"到着して初めて手紙を書いてみます。","ENG":"This is the first letter I've written since arriving.","TWN":"(TWN)도착해서 처음으로 편지를 적어 봅니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"며칠 동안은 정말 많이 바빴어요. 시국에 처음 왔을 때가 떠오를 정도로요.","JPN":"何日間は本当にたくさん忙しかったです。時局に初めて来た時が浮び上がる程度でね。","ENG":"So much has changed in just a few days. It reminds me of when I first came to the diocese.","TWN":"(TWN)며칠 동안은 정말 많이 바빴어요. 시국에 처음 왔을 때가 떠오를 정도로요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 많은 분들이 배려해 주신 덕분에 빠르게 적응할 수 있었답니다.","JPN":"でも多くの方々が気配りしてくれたおかげに早く適応することができたんです。","ENG":"Still, thanks to the kindness of many people, I was able to adapt quickly.","TWN":"(TWN)그래도 많은 분들이 배려해 주신 덕분에 빠르게 적응할 수 있었답니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"예하 말씀대로 태스크포스는 세속적인 조직이에요.","JPN":"隷下お話どおりタスクフォースは世俗的な組織です。","ENG":"As Your Excellency said, the Task Force is a secular organization.","TWN":"(TWN)예하 말씀대로 태스크포스는 세속적인 조직이에요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 태스크포스를 움직이는 사람들은 아니에요.","JPN":"しかしタスクフォースを動かす人々はいやです。","ENG":"But the people who move the Task Force are not.","TWN":"(TWN)하지만 태스크포스를 움직이는 사람들은 아니에요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"어떤 사람은 돈을 버는 게 목적이지만, 또 어떤 사람은 돈이 수단에 불과해요. ","JPN":"ある人はお金を稼ぐのが目的だが、またある人はお金が手段に過ぎないです。","ENG":"For some, earning money is the goal, while for others, money is merely a means.","TWN":"(TWN)어떤 사람은 돈을 버는 게 목적이지만, 또 어떤 사람은 돈이 수단에 불과해요. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"자신의 꿈을 이루기 위해 하루하루 열심히 살아가는 거겠죠.","JPN":"自分の夢をつかむために一日一日熱心に生きて行くことでしょう。","ENG":"They must be living each day diligently to achieve their dreams.","TWN":"(TWN)자신의 꿈을 이루기 위해 하루하루 열심히 살아가는 거겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"저도 이곳에서 많은 사람들을 지킬 수 있었어요.","JPN":"私もここで多くの人を守ることができました。","ENG":"I too was able to protect many people here.","TWN":"(TWN)저도 이곳에서 많은 사람들을 지킬 수 있었어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"태스크포스에는 위험한 의뢰가 많이 들어오거든요.","JPN":"タスクフォースには危ない依頼がたくさん入って来るんですよ。","ENG":"Dangerous requests come into the Task Force often.","TWN":"(TWN)태스크포스에는 위험한 의뢰가 많이 들어오거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘은 구내 식당에서 요리를 돕기도 했어요.","JPN":"今日は構内食堂で料理を助けたりしました。","ENG":"Today, I also helped with cooking at the cafeteria.","TWN":"(TWN)오늘은 구내 식당에서 요리를 돕기도 했어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 분들이 맛있게 드셔 주셨어요. 처음 있는 일이라 그런지 정말 기뻤답니다. ","JPN":"多くの方々がおいしく召し上がってくれました。初めてある事だからか本当に嬉しかったそうです。","ENG":"Many people enjoyed the meal. Perhaps because it was my first time, I was truly happy.","TWN":"(TWN)많은 분들이 맛있게 드셔 주셨어요. 처음 있는 일이라 그런지 정말 기뻤답니다. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"식당에서 일하는 분들도 직업에 무척 열정적이세요. 다음번엔 안 와도 된다고 극구 사양하시더라고요.","JPN":"食堂で働く方々も職業にすごく情熱的ですか。次回には来なくても良いと口を極めて遠慮するんですよ。","ENG":"The people working at the cafeteria are also very passionate about their jobs. They strongly declined, saying I don't need to come next time.","TWN":"(TWN)식당에서 일하는 분들도 직업에 무척 열정적이세요. 다음번엔 안 와도 된다고 극구 사양하시더라고요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘은 대 침식전도 취소되어서 그런지 사옥이 무척 한산해요. ","JPN":"今日は大侵食前も取り消しされるせいか社屋がすごく閑散とします。","ENG":"Perhaps because the Great Erosion Battle was canceled today, the dining hall is quite empty.","TWN":"(TWN)오늘은 대 침식전도 취소되어서 그런지 사옥이 무척 한산해요. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"모처럼 가까운 성당에 가 볼까 합니다.","JPN":"せっかく近い聖堂に行ってみるかと思います。","ENG":"I think I'll visit a nearby church for the first time in a while.","TWN":"(TWN)모처럼 가까운 성당에 가 볼까 합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"비록 몸은 먼 곳에 있지만, 루퍼 자매님의 안녕을 위해 기도하려고 해요.","JPN":"たとえ体は遠い所にあるが、ルーパー姉妹様の安寧のために祈ろうとします。","ENG":"Although my body is far away, I intend to pray for Sister Looper's well-being.","TWN":"(TWN)비록 몸은 먼 곳에 있지만, 루퍼 자매님의 안녕을 위해 기도하려고 해요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"다음에 다시 편지를 부치도록 할게요. 답장 기다리겠습니다.","JPN":"次にまた手紙を送るようにしますよ。ご返事お待ちします。","ENG":"I'll send another letter next time. I look forward to your reply.","TWN":"(TWN)다음에 다시 편지를 부치도록 할게요. 답장 기다리겠습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"당신의 친구이자 자매로부터.","JPN":"あなたの友達であり姉妹から。","ENG":"From your friend and sister.","TWN":"(TWN)당신의 친구이자 자매로부터."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":".......","JPN":".......","ENG":".......","TWN":"(TWN)......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"넬슨 자매님이 편지를 부친 당일, 해당 태스크포스 직원들이 집단 복통을 호소했다더군요.","JPN":"ネルソン姉妹様が手紙を送った当日、該当のタスクフォース職員が集団腹痛を訴えたと言う。","ENG":"On the day Sister Nelson sent the letter, I heard the Task Force staff complained of collective stomach pain.","TWN":"(TWN)넬슨 자매님이 편지를 부친 당일, 해당 태스크포스 직원들이 집단 복통을 호소했다더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"어떻게 된 일인지 설명 좀 부탁드립니다. 자매님.","JPN":"どうなった事なのか説明ちょっとお願いします。姉妹様。","ENG":"Please explain what happened, Sister.","TWN":"(TWN)어떻게 된 일인지 설명 좀 부탁드립니다. 자매님."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"걔 요리 겁나 못해.","JPN":"その子料理怖気づいてできない。","ENG":"She's damn terrible at cooking.","TWN":"(TWN)걔 요리 겁나 못해."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"아니, 끔찍하게 못해. 복통으로 끝났으면 다행이지.","JPN":"いや、無残にできない。腹痛で終わったら幸いだ。","ENG":"No, she's horribly bad at it. It's a relief it ended with just stomach pain.","TWN":"(TWN)아니, 끔찍하게 못해. 복통으로 끝났으면 다행이지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"그런데 자기는 죽어도 모르거든. 베네딕트도 걔가 한 요리는 절대 안 먹었어.","JPN":"ところで自分は死んでも知らなかったら。ベネディクトもその子が一料理は絶対食べなかった。","ENG":"But she doesn't know even if she dies. Benedict never ate the food she made either.","TWN":"(TWN)그런데 자기는 죽어도 모르거든. 베네딕트도 걔가 한 요리는 절대 안 먹었어."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"......말로만 듣던 요리치란 거군요. 부엌 출입만 통제하라고 전해 두면 되겠네요.","JPN":"......話に聞いていた料理値とはことですね。台所出入りだけ統制しなさいと伝えておけば良いですね。","ENG":"......So she really is the terrible cook I heard about. I'll tell them to restrict her kitchen access only.","TWN":"(TWN)......말로만 듣던 요리치란 거군요. 부엌 출입만 통제하라고 전해 두면 되겠네요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"무슨 꿍꿍이야?","JPN":"何のクングクングだ?","ENG":"What's your angle?","TWN":"(TWN)무슨 꿍꿍이야?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"네?","JPN":"はい?","ENG":"Excuse me?","TWN":"(TWN)네?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"넬슨 말이야. 사람 한 명 아깝다더니 파견 근무를 보내는 이유가 뭔데.","JPN":"ネルソン言葉だ。人一人惜しいといったら派遣勤務を送る理由が何だ。","ENG":"I mean Nelson. You cherish her so much, so why send her on dispatch duty?","TWN":"(TWN)넬슨 말이야. 사람 한 명 아깝다더니 파견 근무를 보내는 이유가 뭔데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"자매님이 요새 힘들어 하시는 것 같아요. 기분 전환이죠.","JPN":"姉妹様がこの頃苦しがるようです。気分転換ですよ。","ENG":"Sister seems to be struggling lately. It's a change of pace.","TWN":"(TWN)자매님이 요새 힘들어 하시는 것 같아요. 기분 전환이죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"웃기고 자빠졌네. 그럴 거였으면 재난 지역에 보내서 봉사 활동이나 시켰지.","JPN":"笑わせて転がったな。そんなことだったら災難地域に送ってボランティア活動もさせたの。","ENG":"That's hilarious. If that were the case, you'd have sent her to a disaster area for volunteer work.","TWN":"(TWN)웃기고 자빠졌네. 그럴 거였으면 재난 지역에 보내서 봉사 활동이나 시켰지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"으음, 혹시 뭐 하나 걸려 보라는 심보로 쿡쿡 찌르는 겁니까?","JPN":"ううん、もしかして何一つかかってみるというはらわたでちくちく突くのですか?","ENG":"Hmm, are you poking at me hoping to catch something?","TWN":"(TWN)으음, 혹시 뭐 하나 걸려 보라는 심보로 쿡쿡 찌르는 겁니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"내가 무슨 눈깔사탕 하나에 머리통이 표백되는 어린앤 줄 알아?","JPN":"私が何のあめ玉一つに頭通が漂白される幼いアンド紐分かる?","ENG":"Do you think I'm some kid who gets brainwashed by a single lollipop?","TWN":"(TWN)내가 무슨 눈깔사탕 하나에 머리통이 표백되는 어린앤 줄 알아?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"█████ 사태 가지고 여전히 의심하는 거 아냐.","JPN":"█████ 事態持って相変わらず疑うことだろう。","ENG":"You're still suspicious about the █████ Incident, aren't you.","TWN":"(TWN)█████ 사태 가지고 여전히 의심하는 거 아냐."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"그거 공공장소에서 들먹이시면 큰일납니다.","JPN":"それ公共場所で揺り動かせば大変な事になります。","ENG":"You'll be in big trouble if you bring that up in public.","TWN":"(TWN)그거 공공장소에서 들먹이시면 큰일납니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"부정은 못하겠지만요.","JPN":"不正はできないけれども。","ENG":"Though I can't deny it.","TWN":"(TWN)부정은 못하겠지만요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"이게 진짜......","JPN":"これが本当......","ENG":"Is this really......","TWN":"(TWN)이게 진짜......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"전기톱 꺼내기 전에 끝까지 들어 보세요.","JPN":"電気鋸取り出す前に終りまで聞いてみてください。","ENG":"Listen until the end before you take out the chainsaw.","TWN":"(TWN)전기톱 꺼내기 전에 끝까지 들어 보세요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"저도, 부설 3과도 입장이라는 게 있습니다. 찜찜한 일을 제대로 확인도 않고 묻어 버리면 추기경회의에서 무슨 말이 나오겠어요.","JPN":"私も、敷設3とも立場というのがあります。気まずい事を十分に確認もなくてついてしまえば枢機卿会議で何の言葉が出ます。","ENG":"I, and Sub-Department 3, also have our positions to maintain. If we bury a serious matter without proper investigation, what would be said at the Council of Cardinals?","TWN":"(TWN)저도, 부설 3과도 입장이라는 게 있습니다. 찜찜한 일을 제대로 확인도 않고 묻어 버리면 추기경회의에서 무슨 말이 나오겠어요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"전 넬슨 자매님의 신앙심을 믿고 있습니다. 루퍼 자매님도 그러시죠? ","JPN":"全ネルソン姉妹様の信仰心を信じています。ルーパー姉妹様もそうします?","ENG":"I believe in Sister Nelson's faith. You do too, don't you, Sister Looper?","TWN":"(TWN)전 넬슨 자매님의 신앙심을 믿고 있습니다. 루퍼 자매님도 그러시죠? "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"......흥.","JPN":"......ふん。","ENG":"......Hmph.","TWN":"(TWN)......흥."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"그래도 그 사건이 일어났을 때보다는 한결 나아진 것 같지 않습니까.","JPN":"でもその事件が起きた時よりはいっそうよくなったようでないですか。","ENG":"Still, she seems much better than when that incident occurred, doesn't she?","TWN":"(TWN)그래도 그 사건이 일어났을 때보다는 한결 나아진 것 같지 않습니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_QM","text":{"KOREA":"너무 걱정 마세요. 자매님이라면 무슨 일이 있더라도 이겨내실 겁니다.","JPN":"とても心配しないでください。姉妹様なら何かがあっても打ち勝つでしょう。","ENG":"Don't worry too much. If it's Sister, she'll overcome whatever happens.","TWN":"(TWN)너무 걱정 마세요. 자매님이라면 무슨 일이 있더라도 이겨내실 겁니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"......다들 말은 번지르르하지.","JPN":"......みんな言葉は麗麗しいでしょう。","ENG":"......Everyone talks so smoothly.","TWN":"(TWN)......다들 말은 번지르르하지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};